SELECT 
FROM edu_knowledge_point
WHERE deleted = 0

    AND course_id = #{query.courseId}


    AND category_id = #{query.categoryId}


    AND status = #{query.status}


    AND title LIKE CONCAT('%', #{query.title}, '%')

ORDER BY id DESC

SELECT 
FROM edu_knowledge_point
WHERE deleted = 0 AND status = 1
AND course_id = #{courseId}

    AND category_id = #{categoryId}

ORDER BY id DESC

SELECT FROM edu_knowledge_point WHERE deleted = 0 AND status = 1 AND id IN
#{id}
ORDER BY id DESC
